import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  it('should handle happy path', () => {
    const input = 'The quick brown fox jumps over the lazy dog.';
    const result = truncateContent(input, 20);
    expect(result).toBe('The quick brown f...');
  });

  it('should handle edge case', () => {
    const input = 'Short text';
    const result = truncateContent(input, 50);
    expect(result).toBe(input); // No truncation needed
  });

  it('should handle null/empty', () => {
    expect(truncateContent(null as unknown as string)).toBe('');
    expect(truncateContent(undefined as unknown as string)).toBe('');
    expect(truncateContent('')).toBe('');
    expect(truncateContent('0')).toBe('0');
  });
});

